// ============ TOKENS (lib/core/design/tokens.dart) ============
// The single source of truth for every visual value in the app.

abstract class AppColors {
  static const primary   = Color(0xff5b3bff);
  static const secondary = Color(0xff00c1a2);
  static const surface   = Color(0xffffffff);
  static const surfaceDark = Color(0xff121212);
  static const textPrimary = Color(0xff1a1a1a);
  static const textPrimaryDark = Color(0xffeaeaea);
  static const error = Color(0xffb00020);
}

abstract class AppSpacing {
  static const xs = 4.0;
  static const sm = 8.0;
  static const md = 16.0;
  static const lg = 24.0;
  static const xl = 32.0;
  static const xxl = 48.0;
}

abstract class AppRadii {
  static const sm = BorderRadius.all(Radius.circular(4));
  static const md = BorderRadius.all(Radius.circular(8));
  static const lg = BorderRadius.all(Radius.circular(16));
  static const full = BorderRadius.all(Radius.circular(999));
}

abstract class AppTypography {
  static const displayLarge = TextStyle(fontSize: 48, fontWeight: FontWeight.w700, height: 1.2);
  static const headline     = TextStyle(fontSize: 24, fontWeight: FontWeight.w600, height: 1.3);
  static const body         = TextStyle(fontSize: 16, fontWeight: FontWeight.w400, height: 1.5);
  static const caption      = TextStyle(fontSize: 12, fontWeight: FontWeight.w400, height: 1.4);
}

// ============ THEMES (lib/core/design/theme.dart) ============
ThemeData buildLightTheme() => ThemeData(
  useMaterial3: true,
  colorScheme: ColorScheme.fromSeed(seedColor: AppColors.primary),
  scaffoldBackgroundColor: AppColors.surface,
  textTheme: const TextTheme(
    displayLarge: AppTypography.displayLarge,
    headlineMedium: AppTypography.headline,
    bodyMedium: AppTypography.body,
    labelSmall: AppTypography.caption,
  ),
);

ThemeData buildDarkTheme() => ThemeData(
  useMaterial3: true,
  colorScheme: ColorScheme.fromSeed(seedColor: AppColors.primary, brightness: Brightness.dark),
  scaffoldBackgroundColor: AppColors.surfaceDark,
);

// ============ PRIMITIVES (lib/core/design/widgets/app_button.dart) =========
enum AppButtonVariant { primary, secondary, ghost }

class AppButton extends StatelessWidget {
  const AppButton({
    super.key,
    required this.label,
    required this.onPressed,
    this.variant = AppButtonVariant.primary,
    this.loading = false,
    this.icon,
  });

  final String label;
  final VoidCallback? onPressed;
  final AppButtonVariant variant;
  final bool loading;
  final IconData? icon;

  @override
  Widget build(BuildContext context) {
    final child = loading
        ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2))
        : Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (icon != null) ...[Icon(icon, size: 18), const SizedBox(width: AppSpacing.sm)],
              Text(label),
            ],
          );

    return switch (variant) {
      AppButtonVariant.primary => FilledButton(
        style: FilledButton.styleFrom(
          padding: const EdgeInsets.symmetric(horizontal: AppSpacing.lg, vertical: AppSpacing.md),
          shape: const RoundedRectangleBorder(borderRadius: AppRadii.md),
        ),
        onPressed: loading ? null : onPressed,
        child: child,
      ),
      AppButtonVariant.secondary => OutlinedButton(
        onPressed: loading ? null : onPressed,
        child: child,
      ),
      AppButtonVariant.ghost => TextButton(
        onPressed: loading ? null : onPressed,
        child: child,
      ),
    };
  }
}

// ============ COMPOSITE (lib/core/design/widgets/app_empty_state.dart) =====
class AppEmptyState extends StatelessWidget {
  const AppEmptyState({
    super.key,
    required this.title,
    this.message,
    this.actionLabel,
    this.onAction,
  });

  final String title;
  final String? message;
  final String? actionLabel;
  final VoidCallback? onAction;

  @override
  Widget build(BuildContext context) => Center(
    child: Padding(
      padding: const EdgeInsets.all(AppSpacing.xl),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          const Icon(Icons.inbox, size: 64),
          const SizedBox(height: AppSpacing.md),
          Text(title, style: AppTypography.headline),
          if (message != null) ...[
            const SizedBox(height: AppSpacing.sm),
            Text(message!, style: AppTypography.body, textAlign: TextAlign.center),
          ],
          if (actionLabel != null) ...[
            const SizedBox(height: AppSpacing.lg),
            AppButton(label: actionLabel!, onPressed: onAction),
          ],
        ],
      ),
    ),
  );
}

